In Godot Engine 3.x, you can write a first-person controller script using GDScript and apply it to a `KinematicBody` node. Here's a basic example of how you might set up a first-person controller:

```gdscript
# FirstPersonController.gd
extends KinematicBody

var move_speed = 20.0 # Speed in units per second
var turnSpeed = 180.0 # Degrees per second

var forward_movement = 0.0
var side_movement = 0.0

func _process(delta):
    if Input.is_action_pressed("ui_up"):
        forward_movement += 1.0
    if Input.is_action_pressed("ui_down"):
        forward_movement -= 1.0
    if Input.is_action_pressed("ui_left"):
        side_movement -= 1.0
    if Input.is_action_pressed("ui_right"):
        side_movement += 1.0

    var velocity = Vector2()
    if forward_movement != 0 or side_movement != 0:
        velocity.x = side_movement * move_speed * delta
        velocity.y = forward_movement * move_speed * delta

    var rot_degrees = get_node("Camera").get_rotation_degrees()
    var rot_radians = rot_degrees * PI / 180.0
    var new_velocity = velocity.rotated(rot_radians)

    move(new_velocity)

    forward_movement = 0.0
    side_movement = 0.0

func _input(event):
    if event.is_action_pressed("ui_up"):
        forward_movement = 1.0
    if event.is_action_pressed("ui_down"):
        forward_movement = -1.0
    if event.is_action_pressed("ui_left"):
        side_movement = -1.0
    if event.is_action_pressed("ui_right"):
        side_movement = 1.0

func _unhandled_input(event):
    if event.is_action_pressed("ui_turn_left"):
        turnSpeed = -turnSpeed
    if event.is_action_pressed("ui_turn_right"):
        turnSpeed = turnSpeed

    if turnSpeed != 0:
        var rot_degrees = get_node("Camera").get_rotation_degrees()
        var new_rot_degrees = rot_degrees + turnSpeed * delta
        set_node("Camera").set_rotation_degrees(new_rot_degrees)

# In your scene:

# Create a new scene and add a KinematicBody node
# Add a Camera node as a child of the KinematicBody
# Add a FirstPersonController script to the KinematicBody
# Set the Camera as the Control Mode Camera in the Inspector

# In the scene tree, you can control the character by pressing:
# - Up/Down arrows or W/S to move forward/backward
# - Left/Right arrows or A/D to strafe left/right
# - Q/E to turn left/right
